import{c as n,Q as s,j as t,m as o}from"./chunks/framework.Bhbi9jCp.js";const h=JSON.parse('{"title":"体素世界、区块与无限地形的存法","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/01-体素世界-区块与无限地形的存法.md","filePath":"minecraftLearning/01-体素世界-区块与无限地形的存法.md","lastUpdated":1781674740000}'),p={name:"minecraftLearning/01-体素世界-区块与无限地形的存法.md"};function e(l,a,i,c,r,d){return s(),t("div",null,[...a[0]||(a[0]=[o(`<h1 id="体素世界、区块与无限地形的存法" tabindex="-1">体素世界、区块与无限地形的存法 <a class="header-anchor" href="#体素世界、区块与无限地形的存法" aria-label="Permalink to &quot;体素世界、区块与无限地形的存法&quot;">​</a></h1><p>你在 Minecraft 里向一个方向一直走,世界永远不会到尽头。你挖穿一座山、填平一个湖,关游戏再回来,改动还在。但你硬盘上的存档可能就几百 MB。一个&quot;无限大、还能记住你每一次改动&quot;的世界,凭什么塞得进这么点空间?</p><p>这一篇不讲玩法,先把 Minecraft 世界最底层的三件事讲清楚:<strong>世界是什么数据结构、它怎么被切块管理、以及&quot;无限&quot;到底是怎么做到的</strong>。这三件事理解了,后面所有篇——地形生成、渲染、tick、存储——都是顺着它们往下展开。</p><blockquote><p>一句话先记住:<strong>Minecraft 的世界是一个 3D 体素网格,按区块(chunk)切块加载;而&quot;无限世界&quot;的真相不是&quot;存了无限多东西&quot;,而是&quot;地形能用种子+噪声现场算出来,所以根本不存——只存你改过的那部分&quot;。</strong></p></blockquote><hr><h2 id="一、世界的本质-一个-3d-体素网格" tabindex="-1">一、世界的本质:一个 3D 体素网格 <a class="header-anchor" href="#一、世界的本质-一个-3d-体素网格" aria-label="Permalink to &quot;一、世界的本质:一个 3D 体素网格&quot;">​</a></h2><p>先把&quot;方块&quot;这个词从游戏语境里抽出来,看它的数据本质。</p><p>Minecraft 的世界是一个三维的<strong>体素(voxel)网格</strong>——你可以理解成三维版的像素。空间被切成一个个 1×1×1 的格子,每个格子坐标 <code>(x, y, z)</code> 上,存的是&quot;这一格是什么方块&quot;。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>体素网格 = 三维数组,每个格子存一个方块</span></span>
<span class="line"><span></span></span>
<span class="line"><span>       y (高度)</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       │   ┌──┬──┬──┐</span></span>
<span class="line"><span>       │  ╱  ╱  ╱  ╱│</span></span>
<span class="line"><span>       │ ┌──┬──┬──┐ │</span></span>
<span class="line"><span>       │ │石│石│空│ ┤   每个小立方体 = 一个 voxel</span></span>
<span class="line"><span>       │ ├──┼──┼──┤╱    存的不是模型,是&quot;方块种类 + 状态&quot;</span></span>
<span class="line"><span>       │ │土│土│水│</span></span>
<span class="line"><span>       └─┴──┴──┴──┴──── x</span></span>
<span class="line"><span>        ╱</span></span>
<span class="line"><span>       z</span></span></code></pre></div><p>每一格存的不是一个 3D 模型,而是一个<strong>轻量的标识</strong>:方块种类(ID)+ 一些状态(朝向、是否含水、生长阶段……)。这一点至关重要——正因为单格的数据极小,海量方块才有可能被压缩存储。后续篇会讲到,这个&quot;种类 + 状态&quot;在引擎里叫 BlockState,千万个石头其实共享同一个状态对象,格子里只存一个指向它的下标。</p><h3 id="为什么不能把方块当模型来渲染" tabindex="-1">为什么不能把方块当模型来渲染 <a class="header-anchor" href="#为什么不能把方块当模型来渲染" aria-label="Permalink to &quot;为什么不能把方块当模型来渲染&quot;">​</a></h3><p>新手最容易有的误解是:&quot;每个方块是一个立方体模型,渲染就是把它们一个个画出来。&quot;</p><p>算一笔账就知道这条路走不通:</p><ul><li>一个区块底面 16×16,世界高度 384,就是 <code>16 × 16 × 384 ≈ 9.8 万</code>个方块。</li><li>玩家视野范围动辄几十个区块,<strong>视野内轻松上千万、上亿个方块</strong>。</li><li>每个立方体 6 个面、12 个三角形——逐方块提交,几十亿个三角形,任何显卡当场跪下。</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>朴素想法:N 个方块 → N 个立方体模型 → 几十亿三角形 → 炸显卡</span></span>
<span class="line"><span>现实做法:见 03 篇——只画&quot;暴露在空气里的面&quot;,一个区块合并成一个网格</span></span></code></pre></div><p>所以<strong>体素世界的渲染绝不是&quot;逐方块画&quot;</strong>。怎么把上亿方块压成显卡扛得住的几何体,是 <code>03 区块渲染</code> 专门要解决的问题。这里只需要记住一个结论:<strong>方块的存储表示(数据)和渲染表示(几何)是两回事</strong>,中间隔着一层专门的优化。</p><hr><h2 id="二、区块-chunk-世界的管理单位" tabindex="-1">二、区块(Chunk):世界的管理单位 <a class="header-anchor" href="#二、区块-chunk-世界的管理单位" aria-label="Permalink to &quot;二、区块(Chunk):世界的管理单位&quot;">​</a></h2><p>世界这么大,引擎不可能把它整个塞进内存。于是它被切成<strong>区块(chunk)</strong>——这是 Minecraft 里加载、生成、tick、存盘的基本单位。</p><h3 id="区块的尺寸" tabindex="-1">区块的尺寸 <a class="header-anchor" href="#区块的尺寸" aria-label="Permalink to &quot;区块的尺寸&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1 个 Chunk = 16 (x) × 16 (z) × 整个世界高度 (y)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>           ┌────────────────┐  ← 世界顶 (y=320, 1.18+)</span></span>
<span class="line"><span>           │                │</span></span>
<span class="line"><span>           │   一个 Chunk    │     底面 16×16</span></span>
<span class="line"><span>           │   竖直的一根     │     高度 384(从 y=-64 到 y=320)</span></span>
<span class="line"><span>           │   &quot;柱子&quot;        │</span></span>
<span class="line"><span>           │                │</span></span>
<span class="line"><span>           └────────────────┘  ← 世界底 (y=-64, 1.18+)</span></span></code></pre></div><ul><li><strong>底面固定 16×16</strong>,这是历史以来没变过的。</li><li><strong>高度</strong>:1.18 之前是 256(y=0~255),1.18 起扩展到 <strong>384</strong>(y=-64 ~ 319),所以能挖更深、山能更高。</li></ul><h3 id="再切一刀-section-163-子区块" tabindex="-1">再切一刀:Section(16³ 子区块) <a class="header-anchor" href="#再切一刀-section-163-子区块" aria-label="Permalink to &quot;再切一刀:Section(16³ 子区块)&quot;">​</a></h3><p>一根 384 高的柱子还是太大,不好按需处理。所以区块在竖直方向再切成一段段 <strong>16×16×16 的 Section</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Chunk (16 × 16 × 384)</span></span>
<span class="line"><span>  = 24 个 Section 竖直叠起来</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  Section 23   y=304~319</span></span>
<span class="line"><span>  Section 22   y=288~303</span></span>
<span class="line"><span>     ...</span></span>
<span class="line"><span>  Section  0   y=-64~-49</span></span>
<span class="line"><span>  每个 Section = 16³ = 4096 个方块</span></span></code></pre></div><p>Section 才是真正的&quot;工作粒度&quot;:存储用它(每个 Section 一张方块调色板)、光照按它算、网格按它重建。一个全是空气或全是石头的 Section 可以被极度压缩甚至省略——这点在 <code>08 存储</code> 篇会展开。</p><h3 id="只加载你身边的区块" tabindex="-1">只加载你身边的区块 <a class="header-anchor" href="#只加载你身边的区块" aria-label="Permalink to &quot;只加载你身边的区块&quot;">​</a></h3><p>引擎只把<strong>玩家附近的区块</strong>加载进内存。你走动时,前方的区块被加载/生成,身后远处的区块被卸载、存盘。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>       ▒▒▒▒▒▒▒▒▒▒▒          ▒ = 已卸载(不在内存)</span></span>
<span class="line"><span>       ▒░░░░░░░░░▒          ░ = 已加载(在内存,但外圈不更新)</span></span>
<span class="line"><span>       ▒░░░░░░░░░▒          █ = 玩家所在,完整运行</span></span>
<span class="line"><span>       ▒░░░░█░░░░▒</span></span>
<span class="line"><span>       ▒░░░░░░░░░▒          你往右走 →</span></span>
<span class="line"><span>       ▒░░░░░░░░░▒          右边新区块加载,左边旧区块卸载存盘</span></span>
<span class="line"><span>       ▒▒▒▒▒▒▒▒▒▒▒</span></span></code></pre></div><p>注意&quot;加载&quot;也不是非黑即白:区块有不同的活跃等级,有的完整 tick,有的只是加载着但几乎不更新。这套&quot;区块加载等级&quot;决定了远处的农场会不会停摆,是 <code>05 区块的生命</code> 的主题。这里先建立一个印象:<strong>任意时刻活在内存里的,只是整个无限世界里你周围一小圈。</strong></p><hr><h2 id="三、-无限世界-的真相-能算出来的就不存" tabindex="-1">三、&quot;无限世界&quot;的真相:能算出来的就不存 <a class="header-anchor" href="#三、-无限世界-的真相-能算出来的就不存" aria-label="Permalink to &quot;三、&quot;无限世界&quot;的真相:能算出来的就不存&quot;">​</a></h2><p>现在回到开头那个问题:一个无限大的世界,怎么可能存得下?</p><p>答案是——<strong>它根本不存&quot;地形&quot;</strong>。</p><h3 id="地形是算出来的-不是存出来的" tabindex="-1">地形是算出来的,不是存出来的 <a class="header-anchor" href="#地形是算出来的-不是存出来的" aria-label="Permalink to &quot;地形是算出来的,不是存出来的&quot;">​</a></h3><p>Minecraft 的地形由<strong>程序化生成</strong>:用一组<strong>噪声函数</strong>,输入坐标,输出&quot;这里该是什么&quot;。关键性质是<strong>确定性</strong>:</p><blockquote><p>同一个<strong>种子(seed)</strong> + 同一个<strong>坐标</strong>,噪声函数永远输出相同的结果。</p></blockquote><p>这意味着第 1000 万格的那座山,不需要存在硬盘里——任何时候需要它,拿种子和坐标<strong>当场重新算一遍</strong>,得到的山一模一样。你没去过的地方,在磁盘上<strong>根本不存在</strong>,走过去的瞬间才被生成出来。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>传统思路:世界 = 一份巨大的地形数据,全部存盘   → 无限世界 = 无限存储 ❌</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Minecraft:世界 = 种子(几个字节) + 确定性噪声函数</span></span>
<span class="line"><span>          某坐标的地形 = f(种子, 坐标)  ← 要用时现算,不存 ✅</span></span></code></pre></div><h3 id="那你的改动呢-——只存-差异" tabindex="-1">那你的改动呢?——只存&quot;差异&quot; <a class="header-anchor" href="#那你的改动呢-——只存-差异" aria-label="Permalink to &quot;那你的改动呢?——只存&quot;差异&quot;&quot;">​</a></h3><p>如果地形全靠现算,你挖掉的方块、盖的房子怎么办?</p><p>很简单:<strong>只有被你改动过的区块,才会被写进硬盘。</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>某个区块第一次被访问</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   ├─ 玩家从没改过它  → 不写盘。下次需要时用种子重新生成,结果一致</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   └─ 玩家改动过(挖了/放了方块) → 标记为 dirty,卸载/存档时写入磁盘</span></span>
<span class="line"><span>                                    以后从磁盘读,不再用噪声生成</span></span></code></pre></div><p>所以存档大小<strong>只正比于你实际探索并改造过的范围</strong>,而不是世界的&quot;总大小&quot;(那是无限的)。这就是几百 MB 存档能撑起&quot;无限世界&quot;的全部秘密。</p><p>这套&quot;差异存储&quot;具体怎么落到文件里——哪些区块写进哪个文件、用什么格式——是 <code>07 存储(上)</code> 和 <code>08 存储(下)</code> 的内容。</p><h3 id="这是贯穿全系列的一招" tabindex="-1">这是贯穿全系列的一招 <a class="header-anchor" href="#这是贯穿全系列的一招" aria-label="Permalink to &quot;这是贯穿全系列的一招&quot;">​</a></h3><p>请记住这个思路,因为它不止用在地形上,而是<strong>整个 Minecraft 引擎反复使用的核心招式</strong>:</p><blockquote><p><strong>能算出来的就不存,能共享的就不复制。</strong></p></blockquote><table tabindex="0"><thead><tr><th>场景</th><th>这一招的体现</th><th>哪一篇细讲</th></tr></thead><tbody><tr><td>无限地形</td><td>不存地形,靠种子+噪声现算</td><td><code>01</code>(本篇)/ <code>02</code></td></tr><tr><td>方块状态</td><td>千万个石头共享一个状态对象,格子只存下标</td><td><code>09</code></td></tr><tr><td>区块存储</td><td>只存改过的区块;均质 Section 压到近乎为零</td><td><code>07</code> / <code>08</code></td></tr><tr><td>内存与磁盘</td><td>两边用同构的调色板结构,加载几乎不做转换</td><td><code>03</code> / <code>08</code></td></tr></tbody></table><p>整个系列你都会一次次看到它。Minecraft 的&quot;省&quot;和&quot;快&quot;,大半来自这一句话。</p><hr><h2 id="四、踩坑与反直觉" tabindex="-1">四、踩坑与反直觉 <a class="header-anchor" href="#四、踩坑与反直觉" aria-label="Permalink to &quot;四、踩坑与反直觉&quot;">​</a></h2><p>把这一篇容易误解的点单独拎出来:</p><ul><li><p><strong>&quot;方块是一个个模型&quot;——错。</strong> 方块在数据层是&quot;种类+状态&quot;的轻量标识,在渲染层会被合并成大网格。把它想成模型,你既理解不了存储压缩,也理解不了渲染优化。</p></li><li><p><strong>&quot;世界是一个大数组全在内存里&quot;——错。</strong> 内存里只有你周围一圈区块,而且这一圈还分不同活跃等级。绝大部分世界要么在磁盘上(改过的),要么压根不存在(没去过的)。</p></li><li><p><strong>&quot;无限世界 = 无限存储&quot;——错。</strong> 无限的是&quot;可生成空间&quot;,不是&quot;已存储数据&quot;。没探索的地方零成本,因为它只是种子函数的一个还没被求值的输入。</p></li><li><p><strong>&quot;种子只是个随机数好玩而已&quot;——低估了。</strong> 种子是整个世界确定性的根。同种子同版本,地形可完全复现——这正是&quot;不存也能找回&quot;的前提,也是种子分享、地形预览工具能存在的原因。</p></li><li><p><strong>反直觉的一致性要求:</strong> 因为地形靠&quot;现算&quot;补齐,生成算法<strong>必须严格确定、且跨区块边界自洽</strong>。否则你离开再回来,没改过的地形被重新算出一个不一样的结果,世界就&quot;撕裂&quot;了。这也是为什么地形生成不能简单地&quot;每个区块各算各的&quot;,得有跨区块协调——细节见 <code>02 地形生成</code>。</p></li></ul><hr><h2 id="五、串联" tabindex="-1">五、串联 <a class="header-anchor" href="#五、串联" aria-label="Permalink to &quot;五、串联&quot;">​</a></h2><p>这一篇搭好了地基,三条线从这里岔出去:</p><ul><li><strong>世界怎么&quot;长出来&quot;</strong> → <code>02 地形生成</code> 讲种子和噪声函数到底怎么把坐标变成山川洞穴、怎么保证跨区块自洽。</li><li><strong>世界怎么&quot;画出来&quot;</strong> → <code>03 区块渲染</code> 接着第一节那个&quot;不能逐方块画&quot;的坑,讲怎么只画可见面、把一个区块合并成一次绘制。</li><li><strong>改动怎么&quot;存下来&quot;</strong> → <code>07 / 08 存储</code> 把第三节的&quot;只存差异&quot;落到 Region 文件和 NBT/调色板的字节布局上。</li></ul><p>而本篇反复强调的那句——<strong>能算出来的就不存,能共享的就不复制</strong>——会是你读完整个系列后,对 Minecraft 工程设计最该记住的一句话。</p>`,59)])])}const g=n(p,[["render",e]]);export{h as __pageData,g as default};
